     1→import { pgTable, serial, text, boolean, timestamp, integer } from "drizzle-orm/pg-core";
     2→import { createInsertSchema } from "drizzle-zod";
     3→import { z } from "zod/v4";
     4→
     5→export const sourcesTable = pgTable("sources", {
     6→  id: serial("id").primaryKey(),
     7→  name: text("name").notNull(),
     8→  browseractWorkflowId: text("browseract_workflow_id"),
     9→  promptOverride: text("prompt_override"),
    10→  active: boolean("active").notNull().default(true),
    11→  lastScrapedAt: timestamp("last_scraped_at"),
    12→  preferredScraper: text("preferred_scraper").notNull().default("browseract"),
    13→  createdAt: timestamp("created_at").notNull().defaultNow(),
    14→});
    15→
    16→export const sourceUrlsTable = pgTable("source_urls", {
    17→  id: serial("id").primaryKey(),
    18→  sourceId: integer("source_id").notNull().references(() => sourcesTable.id, { onDelete: "cascade" }),
    19→  url: text("url").notNull(),
    20→  label: text("label"),
    21→  browseractWorkflowId: text("browseract_workflow_id"),
    22→  active: boolean("active").notNull().default(true),
    23→});
    24→
    25→export const insertSourceSchema = createInsertSchema(sourcesTable).omit({ id: true, createdAt: true });
    26→export const insertSourceUrlSchema = createInsertSchema(sourceUrlsTable).omit({ id: true });
    27→export type InsertSource = z.infer<typeof insertSourceSchema>;
    28→export type InsertSourceUrl = z.infer<typeof insertSourceUrlSchema>;
    29→export type Source = typeof sourcesTable.$inferSelect;
    30→export type SourceUrl = typeof sourceUrlsTable.$inferSelect;
