     1→import { Router } from "express";
     2→import { db } from "@workspace/db";
     3→import { sourcesTable, sourceUrlsTable, errorLogsTable } from "@workspace/db/schema";
     4→import { eq, inArray } from "drizzle-orm";
     5→import { requireAuth } from "../middlewares/auth";
     6→import { triggerBrowserActWorkflow } from "../lib/browseract";
     7→import { processRawEvents } from "../lib/eventProcessing";
     8→import { claudeFetchAndExtract } from "../lib/claude";
     9→
    10→const router = Router();
    11→router.use(requireAuth);
    12→
    13→async function getSourceWithUrls(id: number) {
    14→  const [source] = await db.select().from(sourcesTable).where(eq(sourcesTable.id, id)).limit(1);
    15→  if (!source) return null;
    16→  const urls = await db.select().from(sourceUrlsTable).where(eq(sourceUrlsTable.sourceId, id));
    17→  return { ...source, urls };
    18→}
    19→
    20→router.get("/sources", async (_req, res) => {
    21→  const sources = await db.select().from(sourcesTable).orderBy(sourcesTable.name);
    22→  const result = await Promise.all(sources.map(async (s) => {
    23→    const urls = await db.select().from(sourceUrlsTable).where(eq(sourceUrlsTable.sourceId, s.id));
    24→    return { ...s, urls };
    25→  }));
    26→  res.json(result);
    27→});
    28→
    29→router.get("/sources/:id", async (req, res) => {
    30→  const source = await getSourceWithUrls(parseInt(req.params.id));
    31→  if (!source) return res.status(404).json({ error: "Fonte non trovata" });
    32→  res.json(source);
    33→});
    34→
    35→router.post("/sources", async (req, res) => {
    36→  const { name, browseractWorkflowId, promptOverride, active = true, preferredScraper = "browseract", urls = [] } = req.body;
    37→  if (!name) return res.status(400).json({ error: "Nome richiesto" });
    38→  if (!urls.length) return res.status(400).json({ error: "Almeno un URL richiesto" });
    39→
    40→  const [source] = await db.insert(sourcesTable).values({
    41→    name, browseractWorkflowId, promptOverride, active, preferredScraper
    42→  }).returning();
    43→
    44→  for (const url of urls) {
    45→    await db.insert(sourceUrlsTable).values({
    46→      sourceId: source.id, url: url.url, label: url.label || null,
    47→      browseractWorkflowId: url.browseractWorkflowId || null, active: url.active ?? true,
    48→    });
    49→  }
    50→
    51→  const result = await getSourceWithUrls(source.id);
    52→  res.status(201).json(result);
    53→});
    54→
    55→router.put("/sources/:id", async (req, res) => {
    56→  const id = parseInt(req.params.id);
    57→  const { name, browseractWorkflowId, promptOverride, active, preferredScraper, urls } = req.body;
    58→
    59→  await db.update(sourcesTable).set({
    60→    name, browseractWorkflowId, promptOverride, active, preferredScraper
    61→  }).where(eq(sourcesTable.id, id));
    62→
    63→  if (urls) {
    64→    const existingUrls = await db.select().from(sourceUrlsTable).where(eq(sourceUrlsTable.sourceId, id));
    65→    const existingIds = existingUrls.map(u => u.id);
    66→    const incomingIds = urls.filter((u: { id?: number }) => u.id).map((u: { id: number }) => u.id);
    67→    const toDelete = existingIds.filter(id => !incomingIds.includes(id));
    68→    if (toDelete.length) await db.delete(sourceUrlsTable).where(inArray(sourceUrlsTable.id, toDelete));
    69→
    70→    for (const url of urls) {
    71→      if (url.id) {
    72→        await db.update(sourceUrlsTable).set({
    73→          url: url.url, label: url.label || null,
    74→          browseractWorkflowId: url.browseractWorkflowId || null, active: url.active ?? true,
    75→        }).where(eq(sourceUrlsTable.id, url.id));
    76→      } else {
    77→        await db.insert(sourceUrlsTable).values({
    78→          sourceId: id, url: url.url, label: url.label || null,
    79→          browseractWorkflowId: url.browseractWorkflowId || null, active: url.active ?? true,
    80→        });
    81→      }
    82→    }
    83→  }
    84→
    85→  const result = await getSourceWithUrls(id);
    86→  res.json(result);
    87→});
    88→
    89→router.delete("/sources/:id", async (req, res) => {
    90→  const id = parseInt(req.params.id);
    91→  await db.delete(sourcesTable).where(eq(sourcesTable.id, id));
    92→  res.json({ message: "Fonte eliminata" });
    93→});
    94→
    95→async function triggerScrapeForSource(source: typeof sourcesTable.$inferSelect, urls: typeof sourceUrlsTable.$inferSelect[], req: any) {
    96→  const appBaseUrl = process.env.APP_BASE_URL || `https://${process.env.REPLIT_DEV_DOMAIN}`;
    97→  const taskIds: string[] = [];
    98→
    99→  for (const url of urls.filter(u => u.active)) {
   100→    const workflowId = url.browseractWorkflowId || source.browseractWorkflowId;
   101→
   102→    if (source.preferredScraper === "claude_fallback" || !workflowId) {
   103→      // Claude fallback - run inline
   104→      try {
   105→        const { events } = await claudeFetchAndExtract(url.url);
   106→        await processRawEvents(events as any[], source.id, "claude_fallback");
   107→        await db.update(sourcesTable).set({ lastScrapedAt: new Date() }).where(eq(sourcesTable.id, source.id));
   108→      } catch (err) {
   109→        await db.insert(errorLogsTable).values({
   110→          errorType: "scraping_error",
   111→          sourceId: source.id,
   112→          message: `Errore Claude fallback: ${String(err)}`,
   113→          context: { url: url.url },
   114→          resolved: false,
   115→        });
   116→      }
   117→    } else {
   118→      try {
   119→        const callbackUrl = `${appBaseUrl}/api/browseract/webhook/${source.id}/${url.id}`;
   120→        const { taskId } = await triggerBrowserActWorkflow(workflowId, callbackUrl);
   121→        taskIds.push(taskId);
   122→      } catch (err) {
   123→        const errMsg = String(err);
   124→        if (errMsg.includes("QUOTA_EXCEEDED")) {
   125→          await db.insert(errorLogsTable).values({
   126→            errorType: "browseract_quota",
   127→            sourceId: source.id,
   128→            message: "Crediti BrowserAct esauriti",
   129→            context: { url: url.url },
   130→            resolved: false,
   131→          });
   132→        } else {
   133→          await db.insert(errorLogsTable).values({
   134→            errorType: "browseract_error",
   135→            sourceId: source.id,
   136→            message: errMsg,
   137→            context: { url: url.url },
   138→            resolved: false,
   139→          });
   140→          // Fallback to Claude
   141→          try {
   142→            const { events } = await claudeFetchAndExtract(url.url);
   143→            await processRawEvents(events as any[], source.id, "claude_fallback");
   144→          } catch { /* ignore fallback errors */ }
   145→        }
   146→      }
   147→    }
   148→  }
   149→
   150→  await db.update(sourcesTable).set({ lastScrapedAt: new Date() }).where(eq(sourcesTable.id, source.id));
   151→  return taskIds;
   152→}
   153→
   154→router.post("/sources/:id/scrape", async (req, res) => {
   155→  const id = parseInt(req.params.id);
   156→  const [source] = await db.select().from(sourcesTable).where(eq(sourcesTable.id, id)).limit(1);
   157→  if (!source) return res.status(404).json({ error: "Fonte non trovata" });
   158→  const urls = await db.select().from(sourceUrlsTable).where(eq(sourceUrlsTable.sourceId, id));
   159→  const taskIds = await triggerScrapeForSource(source, urls, req);
   160→  res.json({ message: "Scraping avviato", taskIds });
   161→});
   162→
   163→router.post("/sources/scrape-all", async (req, res) => {
   164→  const sources = await db.select().from(sourcesTable).where(eq(sourcesTable.active, true));
   165→  const allTaskIds: string[] = [];
   166→  for (const source of sources) {
   167→    const urls = await db.select().from(sourceUrlsTable).where(eq(sourceUrlsTable.sourceId, source.id));
   168→    const taskIds = await triggerScrapeForSource(source, urls, req);
   169→    allTaskIds.push(...taskIds);
   170→  }
   171→  res.json({ message: `Scraping avviato per ${sources.length} fonti`, taskIds: allTaskIds });
   172→});
   173→
   174→router.post("/sources/:id/import", async (req, res) => {
   175→  const id = parseInt(req.params.id);
   176→  const { events } = req.body;
   177→  if (!Array.isArray(events)) return res.status(400).json({ error: "Array di eventi richiesto" });
   178→  const { saved, errors } = await processRawEvents(events, id, "browseract");
   179→  res.json({ message: `Importati ${saved} eventi, ${errors} errori` });
   180→});
   181→
   182→export default router;
   183→

