     1→import { Switch, Route, Router as WouterRouter } from "wouter";
     2→import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
     3→import { Toaster } from "@/components/ui/toaster";
     4→import { TooltipProvider } from "@/components/ui/tooltip";
     5→
     6→import Login from "./pages/login";
     7→import Dashboard from "./pages/dashboard";
     8→import Fonti from "./pages/fonti";
     9→import Eventi from "./pages/eventi";
    10→import Prompts from "./pages/prompt";
    11→import NewsletterList from "./pages/newsletter";
    12→import NewsletterEdit from "./pages/newsletter-edit";
    13→import Templates from "./pages/template";
    14→import TemplateEdit from "./pages/template-edit";
    15→import Impostazioni from "./pages/impostazioni";
    16→import Utenti from "./pages/utenti";
    17→import NotFound from "./pages/not-found";
    18→
    19→const queryClient = new QueryClient({
    20→  defaultOptions: {
    21→    queries: {
    22→      retry: false,
    23→      refetchOnWindowFocus: false,
    24→    },
    25→  },
    26→});
    27→
    28→function Router() {
    29→  return (
    30→    <Switch>
    31→      <Route path="/login" component={Login} />
    32→      <Route path="/" component={Dashboard} />
    33→      <Route path="/dashboard" component={Dashboard} />
    34→      <Route path="/fonti" component={Fonti} />
    35→      <Route path="/eventi" component={Eventi} />
    36→      <Route path="/prompt" component={Prompts} />
    37→      <Route path="/newsletter" component={NewsletterList} />
    38→      <Route path="/newsletter/:id">{(params) => <NewsletterEdit id={params.id} />}</Route>
    39→      <Route path="/template" component={Templates} />
    40→      <Route path="/template/:id">{(params) => <TemplateEdit id={params.id} />}</Route>
    41→      <Route path="/impostazioni" component={Impostazioni} />
    42→      <Route path="/utenti" component={Utenti} />
    43→      <Route component={NotFound} />
    44→    </Switch>
    45→  );
    46→}
    47→
    48→function App() {
    49→  return (
    50→    <QueryClientProvider client={queryClient}>
    51→      <TooltipProvider>
    52→        <WouterRouter base={import.meta.env.BASE_URL.replace(/\/$/, "")}>
    53→          <Router />
    54→        </WouterRouter>
    55→        <Toaster />
    56→      </TooltipProvider>
    57→    </QueryClientProvider>
    58→  );
    59→}
    60→
    61→export default App;
    62→

