   173→  readonly status: number;
   174→  readonly statusText: string;
   175→  readonly data: T | null;
   176→  readonly headers: Headers;
   177→  readonly response: Response;
   178→  readonly method: string;
   179→  readonly url: string;
   180→
   181→  constructor(
   182→    response: Response,
   183→    data: T | null,
   184→    requestInfo: { method: string; url: string },
   185→  ) {
   186→    super(buildErrorMessage(response, data));
   187→    Object.setPrototypeOf(this, new.target.prototype);
   188→
   189→    this.status = response.status;
   190→    this.statusText = response.statusText;
   191→    this.data = data;
   192→    this.headers = response.headers;
   193→    this.response = response;
   194→    this.method = requestInfo.method;
   195→    this.url = response.url || requestInfo.url;
   196→  }
   197→}
   198→
   199→export class ResponseParseError extends Error {
   200→  readonly name = "ResponseParseError";
   201→  readonly status: number;
   202→  readonly statusText: string;
   203→  readonly headers: Headers;
   204→  readonly response: Response;
   205→  readonly method: string;
   206→  readonly url: string;
   207→  readonly rawBody: string;
   208→  readonly cause: unknown;
   209→
   210→  constructor(
   211→    response: Response,
   212→    rawBody: string,
   213→    cause: unknown,
   214→    requestInfo: { method: string; url: string },
   215→  ) {
   216→    super(
   217→      `Failed to parse response from ${requestInfo.method} ${response.url || requestInfo.url} ` +
   218→        `(${response.status} ${response.statusText}) as JSON`,
   219→    );
   220→    Object.setPrototypeOf(this, new.target.prototype);
   221→
   222→    this.status = response.status;
   223→    this.statusText = response.statusText;
   224→    this.headers = response.headers;
   225→    this.response = response;
   226→    this.method = requestInfo.method;
   227→    this.url = response.url || requestInfo.url;
   228→    this.rawBody = rawBody;
   229→    this.cause = cause;
   230→  }
   231→}
   232→
   233→async function parseJsonBody(
   234→  response: Response,
   235→  requestInfo: { method: string; url: string },
   236→): Promise<unknown> {
   237→  const raw = await response.text();
   238→  const normalized = stripBom(raw);
   239→
   240→  if (normalized.trim() === "") {
   241→    return null;
   242→  }
   243→
   244→  try {
   245→    return JSON.parse(normalized);
   246→  } catch (cause) {
   247→    throw new ResponseParseError(response, raw, cause, requestInfo);
   248→  }
   249→}
   250→
   251→async function parseErrorBody(response: Response, method: string): Promise<unknown> {
   252→  if (hasNoBody(response, method)) {
   253→    return null;
   254→  }
   255→
   256→  const mediaType = getMediaType(response.headers);
   257→
   258→  // Fall back to text when blob() is unavailable (e.g. some React Native builds).
   259→  if (mediaType && !isJsonMediaType(mediaType) && !isTextMediaType(mediaType)) {
   260→    return typeof response.blob === "function" ? response.blob() : response.text();
   261→  }
   262→
   263→  const raw = await response.text();
   264→  const normalized = stripBom(raw);
   265→  const trimmed = normalized.trim();
   266→
   267→  if (trimmed === "") {
   268→    return null;
   269→  }
   270→
   271→  if (isJsonMediaType(mediaType) || looksLikeJson(normalized)) {
   272→    try {
   273→      return JSON.parse(normalized);
   274→    } catch {
   275→      return raw;
   276→    }
   277→  }
   278→
   279→  return raw;
   280→}
   281→
   282→function inferResponseType(response: Response): "json" | "text" | "blob" {
   283→  const mediaType = getMediaType(response.headers);
   284→
   285→  if (isJsonMediaType(mediaType)) return "json";
   286→  if (isTextMediaType(mediaType) || mediaType == null) return "text";
   287→  return "blob";
   288→}
   289→
   290→async function parseSuccessBody(
   291→  response: Response,
   292→  responseType: "json" | "text" | "blob" | "auto",
   293→  requestInfo: { method: string; url: string },
   294→): Promise<unknown> {
   295→  if (hasNoBody(response, requestInfo.method)) {
   296→    return null;
   297→  }
   298→
   299→  const effectiveType =
   300→    responseType === "auto" ? inferResponseType(response) : responseType;
   301→
   302→  switch (effectiveType) {
   303→    case "json":
   304→      return parseJsonBody(response, requestInfo);
   305→
   306→    case "text": {
   307→      const text = await response.text();
   308→      return text === "" ? null : text;
   309→    }
   310→
   311→    case "blob":
   312→      if (typeof response.blob !== "function") {
   313→        throw new TypeError(
   314→          "Blob responses are not supported in this runtime. " +
   315→            "Use responseType \"json\" or \"text\" instead.",
   316→        );
   317→      }
   318→      return response.blob();
   319→  }
   320→}
   321→
   322→export async function customFetch<T = unknown>(
   323→  input: RequestInfo | URL,
   324→  options: CustomFetchOptions = {},
   325→): Promise<T> {
   326→  input = applyBaseUrl(input);
   327→  const { responseType = "auto", headers: headersInit, ...init } = options;
   328→
   329→  const method = resolveMethod(input, init.method);
   330→
   331→  if (init.body != null && (method === "GET" || method === "HEAD")) {
   332→    throw new TypeError(`customFetch: ${method} requests cannot have a body.`);
   333→  }
   334→
   335→  const headers = mergeHeaders(isRequest(input) ? input.headers : undefined, headersInit);
   336→
   337→  if (
   338→    typeof init.body === "string" &&
   339→    !headers.has("content-type") &&
   340→    looksLikeJson(init.body)
   341→  ) {
   342→    headers.set("content-type", "application/json");
   343→  }
   344→
   345→  if (responseType === "json" && !headers.has("accept")) {
   346→    headers.set("accept", DEFAULT_JSON_ACCEPT);
   347→  }
   348→
   349→  // Attach bearer token when an auth getter is configured and no
   350→  // Authorization header has been explicitly provided.
   351→  if (_authTokenGetter && !headers.has("authorization")) {
   352→    const token = await _authTokenGetter();
   353→    if (token) {
   354→      headers.set("authorization", `Bearer ${token}`);
   355→    }
   356→  }
   357→
   358→  const requestInfo = { method, url: resolveUrl(input) };
   359→
   360→  const response = await fetch(input, { ...init, method, headers });
   361→
   362→  if (!response.ok) {
   363→    const errorData = await parseErrorBody(response, method);
   364→    throw new ApiError(response, errorData, requestInfo);
   365→  }
   366→
   367→  return (await parseSuccessBody(response, responseType, requestInfo)) as T;
   368→}
